const { spawn } = require('child_process');

return new Promise((resolve) => {
  const scriptPath = '/app/vps-automation-vhck/scripts/fetch_vsd.py';
  const pythonExe = 'python3';

  const pythonProcess = spawn(pythonExe, [scriptPath]);
  let output = '';
  let errorOutput = '';

  pythonProcess.stdout.on('data', (data) => {
    output += data.toString();
  });

  pythonProcess.stderr.on('data', (data) => {
    errorOutput += data.toString();
  });

  pythonProcess.on('close', (code) => {
    if (code !== 0) {
      resolve([{
        json: {
          error: 'Script exited with code ' + code,
          stderr: errorOutput,
          status: 'error'
        }
      }]);
      return;
    }

    try {
      const vsdData = JSON.parse(output);
      resolve([{ json: { data: vsdData } }]);
    } catch (e) {
      resolve([{
        json: {
          error: 'Failed to parse JSON output',
          message: e.message,
          status: 'error'
        }
      }]);
    }
  });

  pythonProcess.on('error', (error) => {
    resolve([{
      json: {
        error: error.message,
        status: 'error'
      }
    }]);
  });
});

const vsdOutput = $node["1️⃣ Fetch VSD (Tin Tức)"].json;
const vsdResult = vsdOutput.data || vsdOutput;

const allRecords = [];
const recordMap = {};

if (vsdResult && vsdResult.data && Array.isArray(vsdResult.data)) {
  vsdResult.data.forEach(record => {
    allRecords.push({ ...record, source: 'VSD' });
    recordMap[record.code] = record;
  });
}

return [{
  json: {
    vsd_count: vsdResult && vsdResult.count ? vsdResult.count : 0,
    total_unique: allRecords.length,
    vsd_status: vsdResult && vsdResult.status ? vsdResult.status : 'unknown',
    all_records: allRecords,
    vsd_data: vsdResult,
    collected_at: new Date().toISOString()
  }
}];

const fs = require('fs');

const input = $input.first().json;
const records = input.records || [];
const timestamp = new Date().toLocaleString('vi-VN');

const summary = {
  total: records.length,
  vsd: records.length,
  total_unique: records.length,
  pending_confirmation: records.filter(r => r.confirmation_status === 'awaiting_review').length
};

const jsonFilePath = '/app/vps-automation-vhck/vsd_records.json';
const jsonData = {
  source: 'VSD',
  collected_at: new Date().toISOString(),
  timestamp: timestamp,
  total_records: records.length,
  summary: summary,
  records: records
};

fs.writeFileSync(jsonFilePath, JSON.stringify(jsonData, null, 2), 'utf-8');

const markdown = '# Kết Quả Thu Thập Thông Tin Quyền Chứng Khoán\n\n## 📊 Thống Kê\n\n- **Cập nhật lúc:** ' + timestamp + '\n- **Tổng bản ghi (duy nhất):** ' + summary.total + '\n  - VSD: ' + summary.vsd + '\n- **Chờ xác nhận:** ' + summary.pending_confirmation + '\n\n---';

return [{
  json: {
    markdown: markdown,
    records: records,
    summary: summary,
    timestamp: new Date().toISOString(),
    json_file: jsonFilePath,
    json_size: fs.statSync(jsonFilePath).size
  }
}];

const fs = require('fs');
const path = '/app/vps-automation-vhck/result.md';
const input = $input.first().json;
const markdown = input.markdown;
const records = input.records;
const summary = input.summary;

try {
  fs.writeFileSync(path, markdown, 'utf-8');

  return [{
    json: {
      status: 'success',
      message: 'Saved ' + records.length + ' records to result.md',
      file: path,
      timestamp: new Date().toISOString(),
      records_count: records.length,
      summary: summary
    }
  }];
} catch (error) {
  return [{
    json: {
      status: 'error',
      message: error.message,
      file: path
    }
  }];
}

return [{
  json: {
    status: 'success',
    message: 'Workflow hoàn thành!',
    timestamp: new Date().toISOString(),
    next_step: 'Xem result.md để review dữ liệu'
  }
}];
